INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-8b44517b-moex-00117', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「三國時期，晉、吳相爭，吳國大將陸抗生了一場大病，對手晉國大將羊祜善於用兵，且兼 通醫道，派人送了一帖藥給陸抗。陸抗毫不猶疑將藥服用，部屬勸止，擔心羊祜的藥是否可 靠。陸抗說：『羊祜豈鴆人者。』意思是羊祜縱然在沙場與我為敵，但『藥』就是『藥』。 沙場爭馳是一回事，但醫人是另一回事。」 根據上文，下列選項何者最符合文意？', '["陸抗跟羊祜本來就是好朋友", "人道主義應該超越敵我意識", "兩軍對陣不是你死就是我活", "羊祜送藥給陸抗是通敵行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00118', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '頃歲孫莘老識歐陽文忠公，嘗乘閒以文字問之，云：「無它術，唯勤讀書而多為之，自工。 世人患作文字少，又嬾讀書，每一篇出，即求過人，如此少有至者。疵病不必待人指擿，多 作自能見之。」此公以其嘗試者告人，故尤有味。（《東坡志林》） 文中歐陽脩所言，下列選項何者最符合文意？', '["勤讀各種書籍，自然能寫得出佳作", "世人讀書太少，故難掌握撰文訣竅", "只期待每篇盡屬佳作，則不免得罪人", "勤讀書多寫作，便能知自己文章問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00119', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '朱熹〈觀書有感〉：「半畝方塘一鑑開，天光雲影共徘徊。問渠那得清如許？為有源頭活 水來。」 根據上文，下列選項何者最符合文意？', '["將天光雲影加以擬人化，表現雨過初晴的心境", "藉著天機盎然景象，寄託作者悲天憫人的情懷", "藉自然現象為喻，說明讀書可使心靈更加清明", "以所見的自然景象，寄託田園隱居的愉悅心情"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00120', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '人為萬物之靈。性相近，習相遠。與齊人居，不能不齊言也；與楚人居，不能不楚言也。入 芝蘭之室，久而不聞其香，與之俱化矣；入鮑魚之肆，久而不聞其臭，亦與之俱化矣。故曰 一方水土一方人，又曰跟著好人學好人，跟著師婆跳假神。（李光庭《鄉言解頤》） 下列選項，何者最符合上文中對「人」的看法？', '["人具有避惡向善的本性", "人擁有分辨好壞的能力", "人具備改變風俗的能力", "人自然而然受環境影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00121', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「中國書畫收藏史中最著名的『留白煞星』，恐怕就是好大喜功，自封『十全老人』的乾隆 皇帝。他的收藏慾望遠勝其藝術品味，往往在名作上胡亂『塗鴉』。王羲之一張僅二十八字 的《快雪時晴帖》，乾隆卻一口氣蓋上一百七十個印章。在黃公望的《富春山居圖》，他幾 乎將畫圖留白的地方都填滿文字，更把字句直接寫在山石之上，整個富有靈氣的作品毀於一 旦。可幸的是因為乾隆的藝術水平不高，竟然誤把《富》的贗本（子明卷）視為真品，反而 將他同時擁有的真跡（無用師卷）當作贗品，束之高閣並且未題一字。這幅不朽的傳世名作 因此倖免於難，這樣的保存下來。」 根據上文，下列選項何者符合文意？', '["「留白煞星」是收藏家喜歡在留白處蓋印或題字，導致畫面受到破壞", "乾隆為避免破壞留白處，在山石上直接題字，成為特有的藝術重置法", "《富春山居圖》有許多贗本，乾隆將無用師卷保存得宜，只在子明卷題字，不忍破壞真蹟", "因為乾隆有意將真本束之高閣，並且保存得宜，後人才得以見到《富春山居圖》傳世名作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00122', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '《楚辭・漁父》說：「滄浪之水清兮，可以濯我纓；滄浪之水濁兮，可以濯我足。」下列選 項何者最貼近文中所傳達的處世態度？', '["隨波逐流，明哲保身", "千鈞為輕，蟬翼為重", "避世歸隱，方為正途", "擇善固執，各從其志"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00123', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「回來隔離第一天，我坐在窗前看馬路上的活動，發現大部分的車子都是白色的，不知道怎 麼回事。公車的車頂有各種式樣，有天窗的，有圓孔的。騎摩托車的人則像演員一樣，用肢 體表演。我覺得自己就好像剛買回來的金魚，還不能倒入新的水域中，於是和著一些舊的水 裝在袋裡，隔著袋子在看著新世界，而尚不屬於它。」 根據上文，下列選項何者最貼近作者的感受？', '["面對未知未來感到徬徨", "讚嘆市民擁有豐沛活力", "感覺孤獨想要家人陪伴", "對於所見充滿隔閡疑惑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00124', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「對葛蘭姆而言，丹尼雄式的華美服飾，膚淺的情節通通必須拋棄，動作必須強韌獨立地擔 任表達的責任。『一隻舉到半空中的手不代表一棵樹或任何東西。把手舉到半空中，只是動 作與線條本身的美。如此而已。』摸索純淨有力的表達方式，葛蘭姆不厭其煩地以自己和學 生的肢體做試驗品，她在課堂上發展動作語彙，在作品中試驗它的效果。」 根據上文，下列對葛蘭姆舞蹈的敘述正確的是：', '["倚重服飾和情節來增添戲劇張力", "師生在課堂上共同編寫創作而成", "強調以肢體動作為主的表達方式", "公演作品多為實驗性高的半成品"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00125', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「很多人不再有時間去認識東西。他們在商人那裡買現成的東西，但是因為商人並不販賣朋 友，所以很多人沒有朋友。」 根據上文，下列選項最符合文意的是：', '["很多人以為友情是可以用金錢換取，但真正的朋友是無價的", "因為朋友尚未商品化，所以人們無法透過便捷的方式來交友", "人們為了追求速成，不想花時間了解彼此並且等待關係成熟", "工商社會情感淺薄，人際關係疏離因而衍生對朋友過度期待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00126', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列詩句中，何者沒有表達出詩人的自負感和孤獨感？', '["得歡當作樂，斗酒聚比鄰", "前不見古人，後不見來者", "舉杯邀明月，對影成三人", "敏捷詩千首，飄零酒一杯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
